def build_programmatic_icons() -> dict:
    """توليد أيقونات SVG برمجياً (أنماط بسيطة قابلة للتوسعة)."""
    dots = "".join(
        f'<circle cx="{6 + i * 4}" cy="12" r="2" fill="currentColor"/>'
        for i in range(4)
    )
    dwell = (
        f'<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" '
        f'viewBox="0 0 24 24" fill="none">{dots}</svg>'
    )
    rings = "".join(
        f'<circle cx="12" cy="12" r="{4 + i * 3}" stroke="currentColor" '
        f'stroke-width="1.5" fill="none"/>'
        for i in range(3)
    )
    ripple = (
        '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" '
        'viewBox="0 0 24 24" fill="none">' + rings + "</svg>"
    )
    return {"dwell_dots": dwell, "focus_rings": ripple}


ICONS.update(build_programmatic_icons())

